INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('judicial-57f41407-moex-00803', 'judicial-57f41407', 'judicial-57f41407-moex-110-01c5eaab', 'sub-judicial-57f41407-05', NULL, 'single_choice', '「在收垃圾的工人眼裡，你是何等人，只要看所丟的垃圾就行了。什麼等級住宅區倒什麼樣的垃圾， 一點也不會錯。富裕國家的垃圾箱幾乎是百寶箱，有人可以從中把家裡的用具找齊，不費分文，並靠 著垃圾箱活下去。人說『垃圾裡有乾坤』是千真萬確的，因為垃圾透露你的秘密，就像你家送出去的 舊雜誌，把你們的知識水準、經濟能力、注意的事情、嗜好等等，都透露出去了。」 下列敘述，何者最能說明上文的涵義？', '["人們常在不知不覺中，劃分社會階層", "你所丟棄的東西，常顯現自己的訊息", "只要能夠回收，就能夠充分運用資源", "你是金子還是廢物，全由你自己決定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "1ce51c07af4a", "answer_pdf_sha1": "e33fceeebc66", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00804', 'judicial-57f41407', 'judicial-57f41407-moex-110-01c5eaab', 'sub-judicial-57f41407-05', NULL, 'single_choice', '法國小說家雨果說：「歷史與小說皆有真實性，歷史追求客觀的真實，小說追求主觀的真實。」根據 上文，說明正確的選項為：', '["歷史和小說都是真的", "歷史的真實性不容質疑", "小說的真實性是作者塑造的", "歷史和小說的真實性很難區分"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "1ce51c07af4a", "answer_pdf_sha1": "e33fceeebc66", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00805', 'judicial-57f41407', 'judicial-57f41407-moex-110-01c5eaab', 'sub-judicial-57f41407-05', NULL, 'single_choice', '「鏢魚船上的獵人憑藉一艘小船浮在動盪海面。這種傳統鏢刺漁業，除了船隻動力及長鏢桿外，倚賴 的就是眼力、膽識和全船一致的默契，這是一場人魚之間□□□□的海上搏鬥。北風呼嘯，波峰浪谷 聳揚不定，所有的不安，鏢魚船獵人必要以熟練的鏢魚技術為信心，並且一再凝鍊渴望獵物的決心， 才能面對這場海上戰鬥。」 根據上下文意，空格中最適當的用語是：', '["人定勝天", "公平赤裸", "斤斤計較", "爾虞我詐"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "1ce51c07af4a", "answer_pdf_sha1": "e33fceeebc66", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00806', 'judicial-57f41407', 'judicial-57f41407-moex-110-01c5eaab', 'sub-judicial-57f41407-05', NULL, 'single_choice', '「我最愛在夜晚時讀書。邀得前賢到來，把晤言歡，莫逆於心。世間的是非俱謝，再不能勞我心神。 讓自己就像一塊海綿，吸取天地的精華，內在的充實豐盈，將令我走在人生的旅程上一無愧悔。」 依據本文所描述的讀書情境，是因為作者能夠：', '["遠離是非，不惹塵埃", "光風霽月，潔身自愛", "尚友古人，樂在其中", "虛懷若谷，勤奮向學"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "1ce51c07af4a", "answer_pdf_sha1": "e33fceeebc66", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00807', 'judicial-57f41407', 'judicial-57f41407-moex-110-01c5eaab', 'sub-judicial-57f41407-05', NULL, 'single_choice', '「我不曾看到一座單獨的山，山的族群合力鎮住大地；也不曾看到一條孤單的河，水的千手千足皆要 求會合。不曾有過不凋萎的桃花，它們恪守生滅的理則，讓四季與土地完成故事。□，是本份的；□， 也是本份。」 依據文意判斷，文中的缺空處依序應是？', '["動／靜", "分／合", "榮／枯", "聚／散"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "1ce51c07af4a", "answer_pdf_sha1": "e33fceeebc66", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00808', 'judicial-57f41407', 'judicial-57f41407-moex-110-01c5eaab', 'sub-judicial-57f41407-05', NULL, 'single_choice', '「佩玉的人總相信玉是活的，他們說：『玉要戴，戴戴就活起來了哩！』這樣的話是真的嗎？抑或只是 傳說臆想？我不知道自己能不能把一塊玉戴活，這是需要時間才能證明的事，也許幾十年的肌膚相親， 真可以使玉重新有血脈和呼吸。但如果奇蹟是可祈求的，我願意首先活過來的是我，我的清潔質地， 我的緻密堅實，我的瑩秀溫潤，我的斐然紋理，我的清聲遠揚，如果玉可以因人的佩戴而復活，也讓 人因佩玉而復活吧！」 根據上文，作者對於「玉要戴，戴戴就活起來了哩！」這句話的感受最有可能是：', '["深信不疑", "疑信參半", "不置可否", "完全不信"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "1ce51c07af4a", "answer_pdf_sha1": "e33fceeebc66", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00809', 'judicial-57f41407', 'judicial-57f41407-moex-110-01c5eaab', 'sub-judicial-57f41407-05', NULL, 'single_choice', '「英國摩頓爵士死後，他的太太過於悲傷，沒有多久，也追隨她丈夫而去，與她丈夫合葬在一起。當 時英國外交官兼詩人華登寫了兩句詩，作為紀念：『他先死，她試著想獨自活下去，可是不喜歡這樣 的生活，終於也死了！』在短短幾個字中，已包含一大卷小說的內容，為後代留下了一個深戀摯情的 典型。悼亡妻之詩，我最欣賞梅宛陵所作：『結髮為夫妻，於今十七年。相看猶不足，何況是長捐。』 淒婉纏綿，字字自肺腑出，雖其人已亡，而千古後，令人讀之尚有餘情！」 下列選項，最能涵括本文意旨的是：', '["比翼雙飛", "哀毀逾恆", "夫唱婦隨", "詩短情長"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "1ce51c07af4a", "answer_pdf_sha1": "e33fceeebc66", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00810', 'judicial-57f41407', 'judicial-57f41407-moex-110-01c5eaab', 'sub-judicial-57f41407-05', NULL, 'single_choice', '「南飛的雁足，繫不繫濺淚的家書？誰曉得。但確有很多人這樣引頸巴望過。想山疊雲樹，煙迷江南， 後園亭榭那則傳說後來怎樣了呢？後來，漁歌聲中是否還能聽見山寺傳來——一記悠悠清脆的鐘？每 想起，客愁便無從排遣，氣鬚鬚侵上兩頰。一翻身已二十餘年島居歲月。」 根據文意，下列選項流露相同情味的是：', '["兩情若是久長時，又豈在朝朝暮暮", "桃花潭水深千尺，不及汪倫送我情", "泥上偶然留指爪，鴻飛那復計東西", "春風又綠江南岸，明月何時照我還"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "1ce51c07af4a", "answer_pdf_sha1": "e33fceeebc66", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00811', 'judicial-57f41407', 'judicial-57f41407-moex-110-01c5eaab', 'sub-judicial-57f41407-05', NULL, 'single_choice', '「旅行帶給我們快樂與否，或許要看心境而非旅遊的目的地。如果我們能把遊山玩水的那種心境帶入 自己的居住地，可能會發現自己的家，和高山步道或是在南美洲看到的蝴蝶漫天的叢林一樣有趣。」 關於上文的旨趣，下列敘述何者最接近？', '["旅遊是人生得意事可多嘗試", "居住地也可以是有趣的景點", "高山步道漫天蝴蝶才算風景", "遠遊不如在家臥遊何必他求"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "1ce51c07af4a", "answer_pdf_sha1": "e33fceeebc66", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00812', 'judicial-57f41407', 'judicial-57f41407-moex-110-01c5eaab', 'sub-judicial-57f41407-05', NULL, 'single_choice', '「在這段全心全意投入的採訪與寫稿時期間，你朝思暮想著這個人，見到他／她時，你熱情如火，回 家後跟朋友家人喋喋不休討論這個人。日思夜想就是想把這個人解讀得更深一點。這種情感的程度與 力道，必須與愛情相同，但又不可能有任何曖昧。一旦曖昧，寫東西就不客觀，會觸犯專業。這種情 況比較像是熱情的油遇到了水，界線非常明確。」 根據上文，下列何者最符合撰寫採訪人物的心態？', '["對於採訪對象要如陷入熱戀般投入", "堅持客觀筆法是為了避免產生曖昧", "投入的情感與力道必須受專業的審視", "維持投入情感與保持客觀態度的平衡"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "1ce51c07af4a", "answer_pdf_sha1": "e33fceeebc66", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL)
